const statsRaw = $('Fetch Daily Stats').first().json;
const balanceRaw = $('Fetch Balance').first().json;
const geoRaw = $('Fetch Geo Stats').first().json;

const stats = statsRaw.data || statsRaw;
const balance = parseFloat(balanceRaw.data?.balance || balanceRaw.balance || 0);
const geoStats = geoRaw.data || geoRaw;

let totalSpend = 0, totalRevenue = 0, totalClicks = 0, totalShows = 0;
const adPerformance = [];

if (Array.isArray(stats)) {
  stats.forEach(s => {
    const spend = parseFloat(s.money) || 0;
    const revenue = parseFloat(s.postbacks_confirmed_money) || 0;
    const clicks = parseInt(s.clicks_count) || 0;
    const shows = parseInt(s.shows_count) || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;

    totalSpend += spend;
    totalRevenue += revenue;
    totalClicks += clicks;
    totalShows += shows;

    adPerformance.push({ ad_id: s.ad_id, spend, revenue, roi, clicks });
  });
}

// Sort by ROI
adPerformance.sort((a, b) => b.roi - a.roi);

const totalRoi = totalSpend > 0 ? ((totalRevenue - totalSpend) / totalSpend * 100) : 0;
const totalProfit = totalRevenue - totalSpend;

// Best and worst
const top5 = adPerformance.filter(a => a.roi > 0).slice(0, 5);
const worst5 = adPerformance.filter(a => a.roi < 0 && a.spend > 0).slice(-5).reverse();

// Geo breakdown
const geoBreakdown = [];
if (Array.isArray(geoStats)) {
  geoStats.forEach(g => {
    const spend = parseFloat(g.money) || 0;
    const revenue = parseFloat(g.postbacks_confirmed_money) || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
    geoBreakdown.push({ country: g.country_code, spend, revenue, roi: Math.round(roi) });
  });
  geoBreakdown.sort((a, b) => b.roi - a.roi);
}

// Count from DB (approximation from stats)
const activeAds = adPerformance.filter(a => a.clicks > 0).length;

return [{
  json: {
    date: $now.format('yyyy-MM-dd'),
    balance: Math.round(balance * 100) / 100,
    total_spend: Math.round(totalSpend * 100) / 100,
    total_revenue: Math.round(totalRevenue * 100) / 100,
    total_profit: Math.round(totalProfit * 100) / 100,
    total_roi: Math.round(totalRoi * 100) / 100,
    total_clicks: totalClicks,
    total_shows: totalShows,
    active_ads: activeAds,
    top5: top5,
    worst5: worst5,
    geo_breakdown: geoBreakdown.slice(0, 10)
  }
}];

